on start
{
  IP_Endpoint UDP:192.168.1.1:4000 addr;
  addr.SetTransportProtocolToUnknown();
  if (addr.IsTCP())
  {
    write( "Is TCP endpoint" );
  }
  else if (addr.IsUDP())
  {
    write( "Is UDP endpoint" );
  }
  else
  {
    write( "No transport protocol specified for endpoint" );
  }
}
